const resp = $input.first().json;
const extractData = $('Определить маршрут').first().json;
let analysis = {project_key: 'other', topic_query: '', filters: {min_duration_sec: 10, max_duration_sec: 120}};
try {
  const txt = resp.content?.parts?.[0]?.text || resp.text || JSON.stringify(resp);
  const m = txt.match(/\{[\s\S]*\}/);
  if (m) analysis = JSON.parse(m[0]);
} catch(e) {}
analysis.project_key = analysis.project_key || 'other';
analysis.topic_query = analysis.topic_query || 'gameplay';
return [{ json: { chat_id: extractData.chat_id, analysis: analysis } }];

const prev = $('Разобрать ответ Gemini').first().json;
const items = $input.first().json.items || [];

function parseDuration(iso) {
  const m = (iso || '').match(/PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?/);
  if (!m) return 0;
  return (parseInt(m[1]||0)*3600) + (parseInt(m[2]||0)*60) + parseInt(m[3]||0);
}

// Фильтруем: >60 сек, <20 мин, без #shorts в названии
const validVideos = items.filter(v => {
  const dur = parseDuration(v.contentDetails?.duration || '');
  const title = (v.snippet?.title || '').toLowerCase();

  // Исключаем Shorts
  if (title.includes('#shorts') || title.includes('#short')) return false;
  if (dur < 60) return false;  // Shorts обычно <60 сек
  if (dur > 1200) return false;  // Max 20 минут

  return true;
}).slice(0, 5).map((v, idx) => ({
  videoId: v.id,
  title: v.snippet?.title || '',
  duration: parseDuration(v.contentDetails?.duration || ''),
  views: parseInt(v.statistics?.viewCount || 0),
  watch_url: 'https://www.youtube.com/watch?v=' + v.id,
  index: idx
}));

return validVideos.map(video => ({ json: {
  chat_id: prev.chat_id,
  analysis: prev.analysis,
  video: video,
  total_videos: validVideos.length
} }));

const input = $input.first().json;

// r2_key формат: {project}/raw/youtube/{videoId}.mp4
const r2Key = input.r2_key || 'other/raw/youtube/unknown.mp4';
const parts = r2Key.split('/');
const videoId = (parts[parts.length - 1] || '').replace('.mp4', '');

// Используем public_url если сервис его вернул
const publicUrl = input.public_url || null;

return [{ json: { 
  r2_key: r2Key,
  public_url: publicUrl,
  result: { 
    videoId: videoId,
    title: videoId,
    r2_key: r2Key,
    public_url: publicUrl,
    download_success: input.ok === true,
    upload_success: input.ok === true,
    file_size_mb: input.sizeMB || null,
    error: input.error || null
  }
} }];

const items = $input.all();
if (!items.length) return [{ json: { error: 'No results', videos: [], summary: { total: 0, success: 0, failed: 0 } } }];

const results = items.map(i => i.json.result).filter(r => r);
const successCount = results.filter(r => r.upload_success).length;

// Получаем chat_id из начала цепочки
let chatId = 0;
try {
  chatId = $('Фильтр видео').first().json.chat_id || 0;
} catch(e) {
  try {
    chatId = $('Разобрать ответ Gemini').first().json.chat_id || 0;
  } catch(e2) {}
}

return [{ json: { 
  chat_id: chatId,
  summary: { total: results.length, success: successCount, failed: results.length - successCount },
  videos: results
} }];

const d = $input.first().json;

let msg = '✅ Скачано: ' + (d.summary?.success || 0) + '\n\n';

if (d.videos && d.videos.length > 0) {
  d.videos.forEach((v, i) => {
    if (v.upload_success) {
      // Используем public_url если есть, иначе r2_key
