      msg += url + '\n\n';
    }
  });
} else {
  msg += 'Нет ссылок';
}

return [{ json: { chat_id: d.chat_id || 0, text: msg } }];

const data = $input.first().json;
const hasCallback = !!data.callback_query;
const hasMessage = !!data.message;

if (hasCallback) {
  const cb = data.callback_query;
  const action = cb.data || '';

  // Простые коды: yt, px, ai, no
  let intent = 'unknown';
  if (action === 'yt') intent = 'youtube_search';
  else if (action === 'px') intent = 'pexels_search';
  else if (action === 'ai') intent = 'agent_chat';
  else if (action === 'no') intent = 'cancel';

  return [{ json: {
    type: 'callback',
    chat_id: cb.message?.chat?.id || cb.from?.id,
